#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

// Structure for queue node
typedef struct Node {
    char word[11];
    int steps;
    struct Node* next;
} Node;

// Function to create a new queue node
Node* createNode(char* word, int steps) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    strcpy(newNode->word, word);
    newNode->steps = steps;
    newNode->next = NULL;
    return newNode;
}

// Function to check if a word is in the word list
bool isWordInList(char* word, char** wordList, int wordListSize) {
    for (int i = 0; i < wordListSize; i++) {
        if (strcmp(word, wordList[i]) == 0) {
            return true;
        }
    }
    return false;
}

// Function to calculate the length of the shortest transformation sequence
int wordLadderLength(char* startWord, char* targetWord, char** wordList, int wordListSize) {
    Node* front = createNode(startWord, 1);
    Node* rear = front;
    bool* visited = (bool*)calloc(wordListSize, sizeof(bool));

    while (front != NULL) {
        char* word = front->word;
        int steps = front->steps;
        front = front->next;

        if (strcmp(word, targetWord) == 0) {
            return steps;
        }

        for (int i = 0; i < strlen(word); i++) {
            char original = word[i];
            for (char ch = 'a'; ch <= 'z'; ch++) {
                word[i] = ch;
                if (isWordInList(word, wordList, wordListSize)) {
                    Node* newNode = createNode(word, steps + 1);
                    rear->next = newNode;
                    rear = newNode;
                }
            }
            word[i] = original;
        }
    }
    return 0;
}

int main() {
    char* wordList[] = {"des", "der", "dfr", "dgt", "dfs"};
    char* startWord = "der";
    char* targetWord = "dfs";
    int wordListSize = sizeof(wordList) / sizeof(wordList[0]);

    printf("%d\n", wordLadderLength(startWord, targetWord, wordList, wordListSize));
    return 0;
}

